const queries = $('Build People Queries').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const meta = (queries[i] && queries[i].json) ? queries[i].json : {};
  const organic = (items[i].json && Array.isArray(items[i].json.organic)) ? items[i].json.organic : [];
  for (const o of organic) {
    if (!o || !o.link) continue;
    if (!/linkedin\.com\/in\//i.test(o.link)) continue;
    out.push({ json: {
      project_id: meta.project_id,
      owner_company: meta.owner_company,
      title: o.title || '',
      link: o.link,
      snippet: o.snippet || ''
    } });
  }
}
return out;

const src = $('Flatten People Results').all();
const items = $input.all();
const personaFromTitle = (t) => {
  const s = String(t||'').toLowerCase();
  if (/business development|biz dev|product development|sales|marketing|revenue|chief commercial/.test(s)) return null;
  if (/earthwork|grading|excavat|civil work|sitework/.test(s)) return 'earthworks_sub';
  if (/site dev|land dev|real estate|site selection|site acquisit|land acquisit|development (lead|director|manager|head|exec)/.test(s)) return 'site_dev_mgr';
  if (/owner|asset manager|portfolio|investment manager|asset management/.test(s)) return 'owners_rep';
  if (/construction|civil engineering|project (executive|director|manager)|head of project|site manager|delivery/.test(s)) return 'gc_project_exec';
  return null;
};
const rows = [];
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  if (j.error) continue;
  const ex = j.output ? j.output : j;
  const s = (src[i] && src[i].json) ? src[i].json : {};
  const name = String(ex.name || '').trim();
  const title = String(ex.job_title || '').trim();
  const link = String(s.link || '').trim();
  if (!name || !title || !link) continue;
  if (!/linkedin\.com\/in\//i.test(link)) continue;
  const resultText = (String(s.title||'') + ' ' + String(s.snippet||'')).toLowerCase();
  const nameWords = name.toLowerCase().split(/\s+/).filter(w => w.length >= 2);
  if (nameWords.length === 0 || !nameWords.every(w => resultText.includes(w))) continue;
  rows.push({ json: {
    project_id: s.project_id,
    owner_company: s.owner_company,
    contact_name: name,
    contact_title: title,
    persona: personaFromTitle(title),
    contact_linkedin: link
  } });
}
return rows;

