const queries = $('Build Company LinkedIn Queries').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const meta = (queries[i] && queries[i].json) ? queries[i].json : {};
  const organic = (items[i].json && Array.isArray(items[i].json.organic)) ? items[i].json.organic : [];
  let url = null;
  for (const o of organic) {
    if (!o || !o.link) continue;
    if (/^https?:\/\/[a-z]*\.?linkedin\.com\/company\/[^/?]+/i.test(o.link)) {
      url = o.link.split(/[?#]/)[0].replace(/\/$/, '');
      break;
    }
  }
  if (!url) continue;
  out.push({ json: {
    project_id: meta.project_id,
    owner_company: meta.owner_company,
    linkedin_company_url: url
  } });
}
return out;

const src = $('Extract Company LinkedIn URL').all();
const items = $input.all();
// Short-link aliases used in LinkedIn 'website' field — keep Hunter-compatible canonical domain.
const DOMAIN_ALIASES = {
  'goo.gle': 'google.com',
  'fb.com': 'facebook.com',
  'amzn.to': 'amazon.com',
  'apple.co': 'apple.com'
};
const normalize = (d) => DOMAIN_ALIASES[d] || d;
const extractText = (h, marker) => {
  const re = new RegExp('data-test-id="' + marker + '"[\\s\\S]{0,800}?<dd[^>]*>([\\s\\S]{0,500}?)</dd>', 'i');
  const m = h.match(re);
  if (!m) return null;
  const val = m[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
  return val || null;
};
const extractWebsite = (h) => {
  const m = h.match(/about-us__website[\s\S]{0,1500}?(https?:\/\/(?!www\.linkedin\.com|linkedin\.com)([\w-]+(?:\.[\w-]+)+))/i);
  if (!m) return null;
  return normalize(m[2].toLowerCase().replace(/^www\./, ''));
};
const out = [];
for (let i = 0; i < items.length; i++) {
  const meta = (src[i] && src[i].json) ? src[i].json : {};
  const j = items[i].json || {};
  const html = (typeof j.html === 'string') ? j.html : ((typeof j.data === 'string') ? j.data : '');
  if (!html) continue;
  const domain = extractWebsite(html);
  if (!domain) continue;
  out.push({ json: {
    project_id: meta.project_id,
    owner_company: meta.owner_company,
    linkedin_company_url: meta.linkedin_company_url,
    domain: domain,
    industry: extractText(html, 'about-us__industry'),
    hq_location: extractText(html, 'about-us__headquarters'),
    size: extractText(html, 'about-us__size')
  } });
}
return out;
